Absolutely! Here's a comprehensive and efficient C++ program that reads a text file line by line and counts the occurrences of a specific word (case-insensitive and whole word match). The program uses `std::ifstream`, `std::regex`, and `std::unordered_map` for efficient counting.

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <unordered_map>
#include <regex>

int countWordOccurrences(const std::string& filename, const std::string& targetWord) {
    std::unordered_map<std::string, size_t> wordCounts;
    std::regex wordRegex(targetWord, std::regex_constants::icase | std::regex_constants::optimize);

    std::ifstream file(filename);
    if (!file.is_open()) {
        throw std::runtime_error("Cannot open file: " + filename);
    }

    std::string line, matchedWord;
    while (std::getline(file, line)) {
        std::sregex_iterator wordIter(line.begin(), line.end(), wordRegex);
        for (const auto& matchedWord : wordIter) {
            wordCounts[matchedWord.str()]++;
        }
    }

    return wordCounts[targetWord];
}

int main(int argc, char* argv[]) {
    if (argc < 3) {
        std::cerr << "Usage: " << argv[0] << " <file> <word>\n";
        return 1;
    }

    std::string filename = argv[1];
    std::string targetWord = argv[2];
    int count = countWordOccurrences(filename, targetWord);

    std::cout << "The word \"" << targetWord << "\" appears " << count << " times in the file.\n";
}

// Compile with: g++ -std=c++17 -O3 your_program.cpp -o your_program
